-- CONSOLIDAÇÃO E AUDITORIA COMPLETA DE REDES SOCIAIS 2026
-- Plataformas: Facebook & Instagram
-- Período Facebook: 05 de maio de 2025 a 01 de junho de 2026
-- Período Instagram: 02 de maio de 2023 a 02 de maio de 2026
-- Gerado em: 2026-06-03
-- =============================================================================

-- Garantir que colunas necessárias existam em account_metrics antes dos INSERTs
ALTER TABLE public.account_metrics ADD COLUMN IF NOT EXISTS platform TEXT;
ALTER TABLE public.account_metrics ADD COLUMN IF NOT EXISTS clicks_link INTEGER DEFAULT 0;
ALTER TABLE public.account_metrics ADD COLUMN IF NOT EXISTS page_visits INTEGER DEFAULT 0;
ALTER TABLE public.account_metrics ADD COLUMN IF NOT EXISTS earnings NUMERIC(12,6) DEFAULT 0;
ALTER TABLE public.account_metrics ADD COLUMN IF NOT EXISTS ad_revenue NUMERIC(12,6) DEFAULT 0;

