    -- 1. Obter ou criar o ID de usuário do Supabase
    SELECT id INTO v_user_id FROM auth.users LIMIT 1;
    IF v_user_id IS NULL THEN
        v_user_id := 'd09be282-3d73-455b-b9d9-bf2c9183ccbc'; -- Fallback ID
    END IF;

    -- 2. Garantir que as contas de redes sociais existam na tabela social_accounts
    SELECT id INTO v_fb_account_id FROM public.social_accounts WHERE platform = 'facebook' AND platform_user_id = '323348644425052' LIMIT 1;
    IF v_fb_account_id IS NULL THEN
        v_fb_account_id := '0fcc35b1-c6ae-4f81-b8fa-2cb9a55e9ccc';
        INSERT INTO public.social_accounts (id, user_id, platform, platform_user_id, page_name, username, is_connected, created_at, updated_at, followers)
        VALUES (v_fb_account_id, v_user_id, 'facebook', '323348644425052', 'Web Rádio Vitória', '', true, now(), now(), 20921)
        ON CONFLICT (id) DO NOTHING;
    ELSE
        UPDATE public.social_accounts SET followers = 20921, is_connected = true, updated_at = now() WHERE id = v_fb_account_id;
    END IF;

    SELECT id INTO v_ig_account_id FROM public.social_accounts WHERE platform = 'instagram' AND platform_user_id = '17841407384384111' LIMIT 1;
    IF v_ig_account_id IS NULL THEN
        v_ig_account_id := 'b855541f-096b-4696-9a8c-4923f68fe9fb';
