        VALUES (v_ig_account_id, v_user_id, 'instagram', '17841407384384111', 'webradiovitoriaa', 'webradiovitoriaa', true, now(), now(), 82914)
        ON CONFLICT (id) DO NOTHING;
    ELSE
        UPDATE public.social_accounts SET followers = 82914, is_connected = true, updated_at = now() WHERE id = v_ig_account_id;
    END IF;

    -- 3. Limpar métricas antigas das contas no período analisado para evitar duplicidade
    -- Limpeza de métricas históricas de Facebook (05/05/2025 a 01/06/2026)
    DELETE FROM public.account_metrics 
    WHERE social_account_id = v_fb_account_id 
      AND collected_at >= '2025-05-05 00:00:00+00' 
      AND collected_at <= '2026-06-01 23:59:59+00';

